package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP12RegistroContrasenaSeisCaracteresPlaywrightTest extends BaseTestPlaywright {    @Test    void registroConContrasenaExactamenteSeisCaracteres() {        page.navigate("https://ernest.xo.je/index.php?route=auth/register");        String usuarioUnico =                "ltorres" + System.currentTimeMillis();        page.locator("input[name='name']")                .fill("Luis Torres");        page.locator("input[name='username']")                .fill(usuarioUnico);        page.locator("input[name='password']")                .fill("abc123");        page.locator("button[type='submit']")                .click();        page.waitForTimeout(2000);        String contenido = page.content().toLowerCase();        String url = page.url().toLowerCase();        assertTrue(                contenido.contains("login")                        || contenido.contains("iniciar")                        || contenido.contains("registr")                        || url.contains("login"),                "El sistema no aceptó el registro con contraseña de exactamente 6 caracteres."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get(                                "evidencias/HP12-registro-contrasena-seis-caracteres.png"))                        .setFullPage(true)        );    }}